// Repetir a mano no escala:
console.log("Tomatera");
console.log("Albahaca");
console.log("Menta");
// ...y así para cada planta 😩

const huerto = ["Tomatera", "Albahaca", "Menta"];

for (const planta of huerto) {
  console.log(planta);
}
// Muestra las tres, una por vuelta

const dias = [2, 5, 1, 4];   // días sin agua de cada planta
let pendientes = 0;

for (const d of dias) {
  if (d > 3) {
    pendientes++;   // suma 1 al contador
  }
}
console.log(pendientes);   // 2 (la de 5 y la de 4)

const equipos = ["Rojos", "Azules", "Verdes"];

for (let i = 0; i < equipos.length; i++) {
  console.log((i + 1) + ". " + equipos[i]);
}
// 1. Rojos
// 2. Azules
// 3. Verdes

let cuenta = 3;

while (cuenta > 0) {
  console.log(cuenta);
  cuenta--;   // ¡clave! acerca la condición al final
}
console.log("¡Ya!");
// 3, 2, 1, ¡Ya!

